import{_ as a,o as t,c as n,j as r,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"斩首大刀","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/3.B级/斩首大刀.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/3.B级/斩首大刀.md"}'),b={name:"4.资源分区/7.物品与装备/2.武器/近战武器/3.B级/斩首大刀.md"};function d(l,e,_,i,p,c){return t(),n("div",null,[...e[0]||(e[0]=[r("h1",{id:"斩首大刀",tabindex:"-1"},[s("斩首大刀 "),r("a",{class:"header-anchor",href:"#斩首大刀","aria-label":'Permalink to "斩首大刀"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌034")])])],-1),o('<h1 id="斩首大刀-1" tabindex="-1">斩首大刀 <a class="header-anchor" href="#斩首大刀-1" aria-label="Permalink to &quot;斩首大刀&quot;">​</a></h1><p>斩首大刀（改良版）<br> 本质：魔幻本质<br> 价格：B+2500<br> 分类：大刀<br> 体积：4<br> 武器伤害：18L<br> 武器属性：【重型武器】【双手】<br> 描述：<br> 出自《火影忍者》世界观中的武器。为雾隐村忍刀七人众的七忍刀之一。除了巨大的尺寸和锋利的刀刃之外，还能够在杀敌之时汲取对手的血液，用于修复自身的刀身。<br> 然而主神所提供的武器往往极其难以在影片世界当中被破坏，因而轮回空间诗歌塔大能【逆位战车】针对斩首大刀的这一特性进行了改良，令其能够通过汲取敌人的血液增加自己的锋利程度。<br> 效果：<br> 【忍刀】：斩首大刀是出自于《火影忍者》世界中，忍者专用的武器，因而对于查克拉有着良好的适应性。<br> 如果你持有称号：木叶忍者中的下属技能“体术忍者”，那么你可以用一个自由动作，令原本用于强化你的肉身的查克拉流入斩首大刀，从而令所有“体术忍者”中注明“以天生武器进行攻击时”生效的效果在使用这把武器进行攻击时也可以生效。<br> 同时，你可以放弃体术忍者给予你的天生武器伤害提升，令这把武器的武器伤害提升你的查克拉能量池等级*6L。由于给忍刀保持查克拉的注入的消耗更为巨大，因此如果要令这个效果生效，则你每回合必须消耗4点查克拉。<br> 同时如果你将“体术忍者”提升到了A级，则你也可以选择放弃“一回合一次，你可以额外进行一次不附带任何招式的以天生武器进行的攻击”的效果，转而选择一回合一次，你可以额外进行一次不附带任何招式的以具有【忍刀】的白刃武器进行的攻击。<br> 【凶刀饮血】：斩首大刀具有能够吸收对手的血液修复自身的能力，而在经过轮回空间大能的改造之后，这一能力改为可以以敌人的血液增强斩首大刀的锋利程度。<br> 从现在开始，当你以此武器进行攻击时，你每对对手造成3点实际损耗了生命值的伤害，则你可以视为获得了一层【饮血】。无论如何，你一回合最多只能堆叠12层【饮血】，同时【饮血】的堆叠上限为36层。<br> 根据【饮血】的层数，你获得如下收益：<br> 【饮血】累积到12层时，你以斩首大刀进行攻击时，攻击骰的加骰提升一级。<br> 【饮血】累积到24层时，你以斩首大刀进行冲锋白刃攻击时，不再需要承受冲锋减值。<br> 【饮血】累积到36层时，你可以每回合消耗8点查克拉，令你的身周缠绕着令人恐惧的恶鬼的气势。在恶鬼气势缠绕的期间，每回合一次，你以斩首大刀进行的白刃攻击的伤害提升一倍。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',4)])])}const m=a(b,[["render",d]]);export{f as __pageData,m as default};
